import React, { useState } from 'react';
import axios from 'axios';

const AdminPanel = () => {
  const [postType, setPostType] = useState('blog'); // 'job' or 'blog'
  const [category, setCategory] = useState('electronics');
  const [formData, setFormData] = useState({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
  const [file, setFile] = useState(null);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const data = new FormData();
    Object.keys(formData).forEach(key => data.append(key, formData[key]));
    data.append('category', category);
    if (file) data.append('image', file);

    const endpoint = postType === 'job' ? '/api/admin/jobs' : '/api/admin/blog';

    try {
      await axios.post(`http://localhost:5000${endpoint}`, data);
      alert("Post Published Successfully!");
      setFormData({ title: '', description: '', loc: '', salary: '', type: 'On-site' });
    } catch (err) {
      alert("Error publishing post");
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50 pt-20">
      {/* Sidebar */}
      <div className="w-72 bg-black text-white p-10 space-y-8">
        <h2 className="text-2xl font-black text-orange-500 tracking-tighter">HUDSON ADMIN</h2>

        <div>
          <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-4">Post Type</p>
          <button onClick={() => setPostType('job')} className={`w-full text-left p-4 rounded-xl mb-2 font-bold ${postType === 'job' ? 'bg-orange-600' : 'hover:bg-white/10'}`}>Careers / Jobs</button>
          <button onClick={() => setPostType('blog')} className={`w-full text-left p-4 rounded-xl font-bold ${postType === 'blog' ? 'bg-orange-600' : 'hover:bg-white/10'}`}>Service Blogs</button>
        </div>

        {postType === 'blog' && (
          <div>
            <p className="text-[10px] font-black text-gray-500 uppercase tracking-widest mb-4">Select Page</p>
            {['electronics', 'electrical', 'chemical', 'industries'].map(cat => (
              <button key={cat} onClick={() => setCategory(cat)} className={`w-full text-left p-3 rounded-lg mb-1 capitalize text-sm font-bold ${category === cat ? 'text-orange-500' : 'text-gray-400'}`}>
                • {cat}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Form Area */}
      <div className="flex-1 p-16">
        <div className="max-w-3xl bg-white rounded-[3rem] p-12 shadow-sm border border-gray-100">
          <h1 className="text-4xl font-black tracking-tighter mb-10">
            Post to {postType === 'job' ? 'Careers' : category.toUpperCase()}
          </h1>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Title</label>
              <input required className="w-full p-5 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-orange-500 font-bold" 
                value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} />
            </div>

            {postType === 'blog' ? (
              <>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Content / Description</label>
                  <textarea rows="5" className="w-full p-5 bg-gray-50 rounded-2xl outline-none focus:ring-2 focus:ring-orange-500 font-bold"
                    value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})}></textarea>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase tracking-widest text-gray-400 ml-2">Featured Image</label>
                  <input type="file" className="w-full p-4 border-2 border-dashed rounded-2xl" onChange={e => setFile(e.target.files[0])} />
                </div>
              </>
            ) : (
              <div className="grid grid-cols-2 gap-6">
                <input placeholder="Location" className="p-5 bg-gray-50 rounded-2xl outline-none" onChange={e => setFormData({...formData, loc: e.target.value})} />
                <input placeholder="Salary" className="p-5 bg-gray-50 rounded-2xl outline-none" onChange={e => setFormData({...formData, salary: e.target.value})} />
              </div>
            )}

            <button type="submit" className="w-full bg-black text-white py-6 rounded-2xl font-black text-lg hover:bg-orange-600 transition-all shadow-xl">
              Publish Content
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default AdminPanel;
